sp_header_footer.client_script:
api.controller = function ($rootScope, scmNavFlyoverManager) {
    const c = this;

    c.server
        .get({
            action: "loadMenu",
            transactionId: c.data.transactionId,
        })
        .then((response) => {
            c.menuWidget = response.data.menu;
        });

    c.server
        .get({
            action: "getUserInitials",
            transactionId: c.data.transactionId,
        })
        .then((response) => {
            c.userInitials = response.data.userInitials;
        });

    c.server
        .get({
            action: "loadHistory",
            transactionId: c.data.transactionId,
        })
        .then((response) => {
            c.historyWidget = response.data.historyWidget;
        });

    $rootScope.$on("$locationChangeSuccess", function (event, newUrl, oldUrl) {
        c.server.get({
            action: "upsertHistory",
            transactionId: c.data.transactionId,
            url: newUrl,
        });
    });
};

sp_header_footer.css:
.nav,
.breadcrumb {
    background-color: var(--scm-color-sc-white);
    z-index: auto !important;
}

.nav {
    height: var(--scm-spacing-7);
}

.breadcrumb {
    margin-top: 0;
    margin-bottom: 0;
}

.breadcrumb-container {
    margin: 0 3vw;
}

.nav-container {
    display: flex;
    flex-direction: row;
    align-items: center;
    margin-left: 3vw;
    margin-right: 3vw;
    height: inherit;
}

.nav-logo {
    display: flex;
    flex-direction: row;
    align-items: center;
    transform: translateY(-10px);
    height: inherit;
    margin-right: var(--scm-spacing-3) !important;
    margin-left: 0 !important;
}

.nav-actions {
    margin-left: auto;
    display: flex;
    flex-direction: row;
    align-items: center;
    gap: var(--scm-spacing-2);
}

.nav-user {
    background-color: var(--scm-color-sc-navy);
    color: var(--scm-color-sc-white);
    border-radius: 50%;
    border: 0;
    padding: var(--scm-padding-1);
    font-weight: var(--scm-font-weight-semibold);
}

sp_header_footer.script:
(function () {
    const transactionId = input?.transactionId || gs.generateGUID();
    data.transactionId = transactionId;

    const logger = new Logger({
        transactionId: transactionId,
        source: "scm-header.server.js",
        includeTimeStamp: true,
        includeUserInfo: true,
        includeSessionId: true,
    });

    if (!input || !input.action) {
        data.breadcrumbsWidget = $sp.getWidget("scm-navigation-breadcrumbs", {
            transactionId: transactionId,
        });
    }

    if (input && input.action === "getUserInitials") {
        data.userInitials = "AA";
        return;
    }

    if (input && input.action === "loadMenu") {
        const instance = $sp.getValue("sp_rectangle_menu");
        const menu = $sp.getWidgetFromInstance(instance);

        data.menu = JSON.parse(JSON.stringify(menu));
        return;
    }

    if (input && input.action === "upsertHistory") {
        const url = input.url;
        if (!url) {
            logger.error("upsertHistory called with no url");
            return;
        }

        const navigationHistoryHelper = new NavigatorHistory({
            transactionId: transactionId,
        });
        navigationHistoryHelper.upsertHistoryEntry(url);
        return;
    }

    if (input && input.action === "loadHistory") {
        data.historyWidget = $sp.getWidget("scm-history", {
            transactionId: transactionId,
        });
        return;
    }
})();
